import anthropic, asyncio, uuid, json
from hitl_gate import request_approval   # module from above

client = anthropic.AsyncAnthropic()

TOOLS = [
    {
        "name": "send_email",
        "description": "Send an email to a customer.",
        "input_schema": {
            "type": "object",
            "properties": {
                "to":      {"type": "string"},
                "subject": {"type": "string"},
                "body":    {"type": "string"},
            },
            "required": ["to", "subject", "body"],
        },
    },
    {
        "name": "read_crm",
        "description": "Read customer data from the CRM (read-only, safe).",
        "input_schema": {
            "type": "object",
            "properties": {"customer_id": {"type": "string"}},
            "required": ["customer_id"],
        },
    },
]

# Actions that require human approval before execution
APPROVAL_REQUIRED = {"send_email"}

async def run_agent(task: str) -> str:
    messages = [{"role": "user", "content": task}]

    while True:
        response = await client.messages.create(
            model="claude-opus-4-8",
            max_tokens=2048,
            tools=TOOLS,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            # Extract final text
            return next(b.text for b in response.content if b.type == "text")

        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue

            if block.name in APPROVAL_REQUIRED:
                # Pause and ask human
                approved = await request_approval(
                    action_id=block.id,
                    description=f"Send email to {block.input.get('to')}",
                    payload=block.input,
                )
                if not approved:
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": "Action was rejected by human reviewer. Do not retry.",
                    })
                    continue

            # Execute (approved or no approval needed)
            result = await execute_tool(block.name, block.input)
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": json.dumps(result),
            })

        messages.append({"role": "user", "content": tool_results})

async def execute_tool(name: str, args: dict) -> dict:
    if name == "send_email":
        # Actually send the email
        return {"sent": True, "message_id": str(uuid.uuid4())}
    if name == "read_crm":
        return {"customer": {"id": args["customer_id"], "name": "Jane Doe"}}
    return {"error": f"unknown tool: {name}"}

# Measuring HITL overhead in production
import time
from dataclasses import dataclass, field

@dataclass
class HITLMetrics:
    total_actions:    int   = 0
    hitl_actions:     int   = 0
    approved:         int   = 0
    rejected:         int   = 0
    latency_sum_ms:   float = 0.0   # cumulative human review latency

    @property
    def hitl_rate(self) -> float:
        return self.hitl_actions / self.total_actions if self.total_actions else 0.0

    @property
    def approval_rate(self) -> float:
        return self.approved / self.hitl_actions if self.hitl_actions else 0.0

    @property
    def avg_review_latency_ms(self) -> float:
        return self.latency_sum_ms / self.hitl_actions if self.hitl_actions else 0.0

    def record(self, required_hitl: bool, approved: bool = True, latency_ms: float = 0):
        self.total_actions += 1
        if required_hitl:
            self.hitl_actions += 1
            self.latency_sum_ms += latency_ms
            if approved: self.approved += 1
            else:        self.rejected += 1

metrics = HITLMetrics()

# Typical production targets:
# hitl_rate:            < 10% of actions (agent handles the rest autonomously)
# approval_rate:        > 95% (low hitl_rate + low approval_rate signals the agent is uncertain)
# avg_review_latency:   < 5 minutes (longer = agent is blocked and user experience degrades)
